import { getWasmTokenizer } from "@bpinternal/thicktoken";
let tokenizer = null;
export async function getTokenizer() {
  if (!tokenizer) {
    while (!getWasmTokenizer) {
      await new Promise((resolve) => setTimeout(resolve, 25));
    }
    tokenizer = getWasmTokenizer();
  }
  return tokenizer;
}
